mapper.update:
update community_electricity_fee
set fee_status = 'paid',
    payment_time = now(),
    payment_no = #{paymentNo}
where electricity_id = #{electricityId}

mapper.insert:
insert into community_electricity_fee (
    user_id, user_name, user_room, read_month, last_reading, current_reading, used_amount, unit_price, total_fee, balance, fee_status, due_date, payment_time, payment_no, overdue_amount, reader, read_time, remark
) values (
    #{userId}, #{userName}, #{userRoom}, #{readMonth}, #{lastReading}, #{currentReading}, #{usedAmount}, #{unitPrice}, #{totalFee}, #{balance}, #{feeStatus}, #{dueDate}, #{paymentTime}, #{paymentNo}, #{overdueAmount}, #{reader}, #{readTime}, #{remark}
)

mapper.update:
update community_electricity_fee
set balance = balance + #{amount}
where electricity_id = (
    select electricity_id from (
        select electricity_id from community_electricity_fee
        where user_id = #{userId}
        order by electricity_id desc
        limit 1
    ) as temp
)
